console.log('var ilə dəyişən nümunəsi...');
var personName = 'Ayxan';
console.log('Ad:', personName);
// Output:
// var ilə dəyişən nümunəsi...
// Ad: Ayxan

console.log('Yenidən təyin və elan...');
var count = 10;
count = 20; // Yenidən təyin
console.log('Dəyər:', count);
var count = 30; // Yenidən elan
console.log('Yeni dəyər:', count);
// Output:
// Yenidən təyin və elan...
// Dəyər: 20
// Yeni dəyər: 30

console.log('Scope nümunəsi...');
if (true) {
    var message = 'Blok daxilində';
}
console.log('Blok xaricində:', message);
// Output:
// Scope nümunəsi...
// Blok xaricində: Blok daxilində

console.log('Hoisting nümunəsi...');
console.log(value); // Dəyər təyin olunmayıb
var value = 100;
console.log('Təyin olunduqdan sonra:', value);
// Output:
// Hoisting nümunəsi...
// undefined
// Təyin olunduqdan sonra: 100

console.log('var vs let nümunəsi...');
if (true) {
    var varValue = 'Var dəyəri';
    let letValue = 'Let dəyəri';
}
console.log(varValue); // İşləyir
console.log(letValue); // Səhv: letValue is not defined
// Output:
// var vs let nümunəsi...
// Var dəyəri
// Uncaught ReferenceError: letValue is not defined

console.log('Səhvə yol açan nümunə...');
for (var i = 0; i < 3; i++) {
    setTimeout(function() {
        console.log('Dəyər:', i);
    }, 1000);
}
// Output (1 saniyədən sonra):
// Səhvə yol açan nümunə...
// Dəyər: 3
// Dəyər: 3
// Dəyər: 3

