content.code:
console.log('var variable example...');
var personName = 'John';
console.log('Name:', personName);
// Output:
// var variable example...
// Name: John

console.log('Reassignment and redeclaration...');
var count = 10;
count = 20; // Reassignment
console.log('Value:', count);
var count = 30; // Redeclaration
console.log('New value:', count);
// Output:
// Reassignment and redeclaration...
// Value: 20
// New value: 30

console.log('Scope example...');
if (true) {
    var message = 'Inside block';
}
console.log('Outside block:', message);
// Output:
// Scope example...
// Outside block: Inside block

console.log('Hoisting example...');
console.log(value); // Not assigned yet
var value = 100;
console.log('After assignment:', value);
// Output:
// Hoisting example...
// undefined
// After assignment: 100

console.log('var vs let example...');
if (true) {
    var varValue = 'Var value';
    let letValue = 'Let value';
}
console.log(varValue); // Works
console.log(letValue); // Error: letValue is not defined
// Output:
// var vs let example...
// Var value
// Uncaught ReferenceError: letValue is not defined

console.log('Error-prone example...');
for (var i = 0; i < 3; i++) {
    setTimeout(function() {
        console.log('Value:', i);
    }, 1000);
}
// Output (after 1 second):
// Error-prone example...
// Value: 3
// Value: 3
// Value: 3

